// AUTO-GENERATED by @aquila/stories compiler. Do not edit by hand.

import type { DialogueEntry } from '../../../types';
import { CharacterId } from '../characters';
import { Portrait } from '../portraits';
import { Background } from '../backgrounds';

export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "18:10。物件確認室。", background: Background.Chapter_13_Ch13_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "小野寺把預約頁裁切圖還給承辦人。他的手指在紙邊停了一下，像在確認自己沒有留下指紋，又像在確認自己沒有再多看一眼。然後他轉向承辦人。", background: Background.Chapter_13_Ch13_Act4_S0 },
    { characterId: CharacterId.OnoderaNaoki, character: "小野寺", dialogue: "我有個正式請求。", background: Background.Chapter_13_Ch13_Act4_S0, portrait: Portrait.OnoderaNaoki_Guarded },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的語氣變了。前面那段格式說明像在讀手冊，現在這句話像在填表單——每一個字都先在嘴裡排過隊才放出來。", background: Background.Chapter_13_Ch13_Act4_S0 },
    { characterId: CharacterId.OnoderaNaoki, character: "小野寺", dialogue: "希望取得去識別化的第二階段預約頁裁切圖，以及帶比例尺的鏡背裁切圖。供公司安全部門判斷是否涉及跨部門格式誤用，或外部仿冒。", background: Background.Chapter_13_Ch13_Act4_S0, portrait: Portrait.OnoderaNaoki_Guarded },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他要資料。不是要鏡子。要那兩張裁切圖。", background: Background.Chapter_13_Ch13_Act4_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的手指在桌面下動了一下。不是握拳，是那種把什麼東西往自己這邊收的動作。但她沒有東西可收——裁切圖在承辦人手裡，鏡子在證物袋裡。她能收的只有自己的肩膀。", background: Background.Chapter_13_Ch13_Act4_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他沒有要求帶走原件。從頭到尾，他都沒有碰過鏡子。他只看了照片。只看了裁切圖。現在他要的是裁切圖。要帶回公司。要給安全部門。", background: Background.Chapter_13_Ch13_Act4_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "小野寺繼續說。像在補一份申請書的理由欄。", background: Background.Chapter_13_Ch13_Act4_S0 },
    { characterId: CharacterId.OnoderaNaoki, character: "小野寺", dialogue: "公司的地址格式屬於內部規範。如果被外部單位使用，需要確認是否經過授權。跨部門命名規範如果錯誤外露，也屬於資安通報範圍。", background: Background.Chapter_13_Ch13_Act4_S0, portrait: Portrait.OnoderaNaoki_Guarded },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他停了一下。補了最後一句。", background: Background.Chapter_13_Ch13_Act4_S0 },
    { characterId: CharacterId.OnoderaNaoki, character: "小野寺", dialogue: "如果涉及供應商資安，公司需要正式通報。", background: Background.Chapter_13_Ch13_Act4_S0, portrait: Portrait.OnoderaNaoki_Guarded },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯理由很乾淨。每一條都像從資安手冊裡抄出來的。公司格式被外部使用。命名規範外露。資安通報。沒有一條提到孩子。沒有一條提到研究。沒有一條提到悠真。", background: Background.Chapter_13_Ch13_Act4_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "承辦人沒有立刻答應。他把裁切圖放在桌面上，手掌壓住邊緣，像在防止它自己飛走。", background: Background.Chapter_13_Ch13_Act4_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "保存多久？", background: Background.Chapter_13_Ch13_Act4_S0 },
    { characterId: CharacterId.OnoderaNaoki, character: "小野寺", dialogue: "⋯⋯視通報結果而定。通常安全部門會先建檔，再依處理進度決定保留期間。", background: Background.Chapter_13_Ch13_Act4_S0, portrait: Portrait.OnoderaNaoki_Guarded },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "哪個部門可以存取？", background: Background.Chapter_13_Ch13_Act4_S0 },
    { characterId: CharacterId.OnoderaNaoki, character: "小野寺", dialogue: "公共安全系統部的安全窗口。以及——若確認涉及其他部門格式——可能需要轉交教育資料服務部確認。", background: Background.Chapter_13_Ch13_Act4_S0, portrait: Portrait.OnoderaNaoki_Guarded },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯教育資料服務部。", background: Background.Chapter_13_Ch13_Act4_S0, portrait: Portrait.AsakuraMio_Angry },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的呼吸停了半秒。就是那個部門。悠真睡眠研究文件頁尾標著 TKS 的那個部門。小野寺剛才說它和公共安全系統部分開運作。現在他說，裁切圖可能需要轉交過去。", background: Background.Chapter_13_Ch13_Act4_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他把這兩條線接起來了。不是用結論接的。是用「可能需要確認」接的。一句普通的資安流程話。可是它會把悠真的預約頁裁切圖送到那個部門面前。", background: Background.Chapter_13_Ch13_Act4_S0, portrait: Portrait.AsakuraMio_Angry },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "有正式書面請求嗎？", background: Background.Chapter_13_Ch13_Act4_S0 },
    { characterId: CharacterId.OnoderaNaoki, character: "小野寺", dialogue: "⋯⋯目前是現場口頭提出。書面請求要由安全部門發正式文件。", background: Background.Chapter_13_Ch13_Act4_S0, portrait: Portrait.OnoderaNaoki_Guarded },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "TKS 是這件案的關聯供應商。你們同時是系統提供者，也是可能涉及格式外露的一方。這裡面有沒有利益衝突？", background: Background.Chapter_13_Ch13_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "房間安靜了一下。小野寺的眼睛眨了一次。很快。像被閃光燈晃了一下。", background: Background.Chapter_13_Ch13_Act4_S0 },
    { characterId: CharacterId.OnoderaNaoki, character: "小野寺", dialogue: "⋯⋯這部分由公司安全部門與法務判斷。我個人只負責技術格式說明。", background: Background.Chapter_13_Ch13_Act4_S0, portrait: Portrait.OnoderaNaoki_Guarded },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他退了一步。問到利益衝突，他就把「我」縮成「技術格式說明」。他不再代表公司判斷。他只是一個工程師。一個睡眠不足、習慣精確用詞、對刑事程序不自在的工程師。", background: Background.Chapter_13_Ch13_Act4_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "承辦人把這幾個問題的答案寫進紀錄。寫得很慢。每一行都像在稱重量。寫完之後，他放下筆。", background: Background.Chapter_13_Ch13_Act4_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "你的請求超出本次現場詢問的範圍。外部保存要另走程序。我需要向案件負責人確認。", background: Background.Chapter_13_Ch13_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他站起來。拿著紀錄板，走向門口。門開的時候，走廊的燈光切進來。", background: Background.Chapter_13_Ch13_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪看著承辦人的背影消失在門外。房間裡剩下她和兩張裁切圖，和小野寺。", background: Background.Chapter_13_Ch13_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "小野寺沒有看她。他在看自己的手。然後他把手插進口袋。像在確認手不會自己伸出去拿什麼東西。", background: Background.Chapter_13_Ch13_Act4_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他不看我。從剛才到現在，他只跟承辦人說話。他把我當成物主，不是對話對象。他的請求是對警方提的，不是對我。可是他要的東西——那張裁切圖——上面是悠真的預約頁。是我的。是悠真的。不是公司的格式樣本。", background: Background.Chapter_13_Ch13_Act4_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "門又開了。", background: Background.Chapter_13_Ch13_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這次進來的不是承辦人一個人。他身後跟著一個人。深色西裝。舊皮鞋。鞋底磨偏了。", background: Background.Chapter_13_Ch13_Act4_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯日下部。", background: Background.Chapter_13_Ch13_Act4_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "日下部悟。警視廳刑警。他走進來的時候沒有看她。他先看桌上的裁切圖。再看小野寺。再看承辦人手裡的紀錄板。最後才看見她——或者假裝才看見她。", background: Background.Chapter_13_Ch13_Act4_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他本來就在這層樓。承辦人去確認案件負責人，他就跟過來了。他不需要被叫。他就在這裡。千田死亡、悠真失蹤、交叉報告——這些都在同一層樓。他隨時可以走進任何一間房間。", background: Background.Chapter_13_Ch13_Act4_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "日下部沒有坐下。他站在桌邊，翻開承辦人的紀錄板，看了幾行。他的眼睛在紙面上移動的速度很快，像在找一個特定的字。", background: Background.Chapter_13_Ch13_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他找到了。他的視線停在小野寺的請求那一段。", background: Background.Chapter_13_Ch13_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後他抬起頭。看承辦人。", background: Background.Chapter_13_Ch13_Act4_S0 },
    { characterId: CharacterId.KusakubeSatoru, character: "日下部", dialogue: "他的說法記成供應商技術說明。不是鑑定。", background: Background.Chapter_13_Ch13_Act4_S0, portrait: Portrait.KusakubeSatoru_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "語氣平。像在改一個錯字。像那天晚上在站務室裡，他把「刃物狀金屬片」改成「金屬外殼狀物」一樣——六個字的差別，決定後面的人用什麼角度去看它。", background: Background.Chapter_13_Ch13_Act4_S0 },
    { characterId: CharacterId.KusakubeSatoru, character: "日下部", dialogue: "外部保存另走書面程序。", background: Background.Chapter_13_Ch13_Act4_S0, portrait: Portrait.KusakubeSatoru_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "承辦人點頭。在紀錄板上改了幾個字。", background: Background.Chapter_13_Ch13_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "日下部轉向小野寺。", background: Background.Chapter_13_Ch13_Act4_S0 },
    { characterId: CharacterId.KusakubeSatoru, character: "日下部", dialogue: "今天可以在這裡看。", background: Background.Chapter_13_Ch13_Act4_S0, portrait: Portrait.KusakubeSatoru_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他頓了一下。像在確認下一句的重量。", background: Background.Chapter_13_Ch13_Act4_S0 },
    { characterId: CharacterId.KusakubeSatoru, character: "日下部", dialogue: "要帶回公司，先發正式照會。寫清楚保存部門和用途。", background: Background.Chapter_13_Ch13_Act4_S0, portrait: Portrait.KusakubeSatoru_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "小野寺沒有爭執。他的肩膀鬆了一點——不是放鬆，是那種被一個明確邊界接住的鬆。他不需要自己判斷能拿多少。邊界已經被畫好了。", background: Background.Chapter_13_Ch13_Act4_S0 },
    { characterId: CharacterId.OnoderaNaoki, character: "小野寺", dialogue: "那我先只提供格式說明。", background: Background.Chapter_13_Ch13_Act4_S0, portrait: Portrait.OnoderaNaoki_Guarded },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他停了一下。把剩下的話補完。", background: Background.Chapter_13_Ch13_Act4_S0 },
    { characterId: CharacterId.OnoderaNaoki, character: "小野寺", dialogue: "公司若要正式確認，再由安全部門發函。", background: Background.Chapter_13_Ch13_Act4_S0, portrait: Portrait.OnoderaNaoki_Guarded },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他沒有爭。他沒有說「可是資安流程需要盡快」。他沒有說「這涉及公司責任」。他接受了。一個工程師接受一個刑警畫的程序邊界。像兩個人都知道，這個房間裡誰的話算數。", background: Background.Chapter_13_Ch13_Act4_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "日下部沒有再說話。他合上紀錄板，遞還給承辦人。動作不重，但遞的時候他的手指在板緣停了一秒——像在確認承辦人接住了。", background: Background.Chapter_13_Ch13_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後他看了澪一眼。", background: Background.Chapter_13_Ch13_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "只一眼。沒有點頭，沒有搖頭，沒有任何她能解讀的東西。像在確認她還在這裡。像在確認她沒有把什麼東西交出去。", background: Background.Chapter_13_Ch13_Act4_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他在看我。不是在幫我。也不是在害我。他在確認一件事——我沒有在這個房間裡，把悠真的東西交給一個我不該信任的人。", background: Background.Chapter_13_Ch13_Act4_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "日下部轉身。走向門口。皮鞋在地面上刮了一聲。", background: Background.Chapter_13_Ch13_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有回頭。", background: Background.Chapter_13_Ch13_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "門帶上。走廊的燈光被切斷。房間又回到那種白色的、均勻的、像沒有時間的亮。", background: Background.Chapter_13_Ch13_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "小野寺站在原處。他的手還插在口袋裡。他看了一眼桌上的裁切圖——那一眼很短，像在記住什麼，又像在告別什麼——然後他把視線收回來。", background: Background.Chapter_13_Ch13_Act4_S0 },
    { characterId: CharacterId.OnoderaNaoki, character: "小野寺", dialogue: "⋯⋯格式說明的部分，剛才已經提供完了。", background: Background.Chapter_13_Ch13_Act4_S0, portrait: Portrait.OnoderaNaoki_Guarded },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他對承辦人說的。像在宣告自己已經沒有別的東西可以給了。", background: Background.Chapter_13_Ch13_Act4_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "了解。今天的供應商技術說明到此。", background: Background.Chapter_13_Ch13_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "承辦人在紀錄板上寫下時間。18:38。", background: Background.Chapter_13_Ch13_Act4_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他沒有拿到裁切圖。他只提供了格式說明。那兩張裁切圖還在警方手裡。沒有被帶回公司。沒有被轉交教育資料服務部。沒有被放進任何安全窗口的檔案。", background: Background.Chapter_13_Ch13_Act4_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看著桌上的裁切圖。預約頁那張。鏡背那張。它們還在那裡。還沒有被任何人收走。", background: Background.Chapter_13_Ch13_Act4_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯可是他知道它們存在了。小野寺知道。日下部知道。承辦人知道。這個房間裡的每一個人都知道——有一張預約頁，上面寫著 G07／12。有一面鏡子，背後刻著部分相符的筆畫。這件事已經被看見了。我把它放進程序，就是為了讓它被看見。可是被看見之後，誰會先伸手——我不知道。", background: Background.Chapter_13_Ch13_Act4_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "18:40。小野寺收拾自己的東西。一個舊款公事包。一個保溫杯。他沒有帶走任何屬於這件案的資料。", background: Background.Chapter_13_Ch13_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他走到門口。沒有回頭。沒有再說什麼。門帶上。走廊的燈光被切斷。", background: Background.Chapter_13_Ch13_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "房間裡只剩承辦人和她。", background: Background.Chapter_13_Ch13_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "還有那面小鏡子。在證物袋裡。還沒有被還給她。", background: Background.Chapter_13_Ch13_Act4_S0 },
];
